CREATE OR REPLACE FUNCTION public.calculate_player_attributes(p_posicao text, p_arquetipo text, p_altura text, p_peso text)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
    v_base JSONB;
    v_modifiers JSONB;
    v_final JSONB;
    v_height_m NUMERIC := NULL;
    v_weight_kg NUMERIC := NULL;
    v_bmi NUMERIC;
    v_severity NUMERIC := 0;

    v_preset_key TEXT := p_posicao || ':' || p_arquetipo;
    v_normalized_altura TEXT;
    v_normalized_peso TEXT;

    pos_fisico INT := 0; pos_marcacao INT := 0; pos_finalizacao INT := 0; pos_velocidade INT := 0; pos_passe INT := 0; pos_visao INT := 0;
    neg_fisico INT := 0; neg_marcacao INT := 0; neg_finalizacao INT := 0; neg_velocidade INT := 0; neg_passe INT := 0; neg_visao INT := 0;

    v_pos_weights attribute_weight[];
    v_neg_weights attribute_weight[];

    v_total INT;
    v_pos_dist JSONB;
    v_neg_dist JSONB;

    v_mod_fisico INT; v_mod_marcacao INT; v_mod_finalizacao INT; v_mod_velocidade INT; v_mod_passe INT; v_mod_visao INT;
BEGIN
    -- 1. Base Attributes
    CASE v_preset_key
        WHEN 'Atacante:Finalizador' THEN v_base := '{"Finaliza├º├úo": 61, "F├¡sico": 52, "Passe": 48, "Marca├º├úo": 35, "Velocidade": 59, "Vis├úo de jogo": 50}';
        WHEN 'Atacante:Driblador' THEN v_base := '{"Finaliza├º├úo": 54, "F├¡sico": 45, "Passe": 51, "Marca├º├úo": 34, "Velocidade": 63, "Vis├úo de jogo": 56}';
        WHEN 'Atacante:Criador' THEN v_base := '{"Finaliza├º├úo": 50, "F├¡sico": 44, "Passe": 61, "Marca├º├úo": 35, "Velocidade": 55, "Vis├úo de jogo": 63}';
        WHEN 'Atacante:Ra├ºudo' THEN v_base := '{"Finaliza├º├úo": 54, "F├¡sico": 62, "Passe": 44, "Marca├º├úo": 48, "Velocidade": 56, "Vis├úo de jogo": 46}';
        WHEN 'Meia:Finalizador' THEN v_base := '{"Finaliza├º├úo": 56, "F├¡sico": 48, "Passe": 60, "Marca├º├úo": 43, "Velocidade": 53, "Vis├úo de jogo": 59}';
        WHEN 'Meia:Driblador' THEN v_base := '{"Finaliza├º├úo": 49, "F├¡sico": 44, "Passe": 59, "Marca├º├úo": 42, "Velocidade": 61, "Vis├úo de jogo": 61}';
        WHEN 'Meia:Criador' THEN v_base := '{"Finaliza├º├úo": 44, "F├¡sico": 43, "Passe": 63, "Marca├º├úo": 45, "Velocidade": 51, "Vis├úo de jogo": 65}';
        WHEN 'Meia:Ra├ºudo' THEN v_base := '{"Finaliza├º├úo": 44, "F├¡sico": 60, "Passe": 55, "Marca├º├úo": 57, "Velocidade": 50, "Vis├úo de jogo": 57}';
        WHEN 'Zagueiro:Finalizador' THEN v_base := '{"Finaliza├º├úo": 41, "F├¡sico": 62, "Passe": 47, "Marca├º├úo": 61, "Velocidade": 47, "Vis├úo de jogo": 48}';
        WHEN 'Zagueiro:Driblador' THEN v_base := '{"Finaliza├º├úo": 36, "F├¡sico": 58, "Passe": 50, "Marca├º├úo": 59, "Velocidade": 54, "Vis├úo de jogo": 51}';
        WHEN 'Zagueiro:Criador' THEN v_base := '{"Finaliza├º├úo": 34, "F├¡sico": 57, "Passe": 58, "Marca├º├úo": 61, "Velocidade": 45, "Vis├úo de jogo": 58}';
        WHEN 'Zagueiro:Ra├ºudo' THEN v_base := '{"Finaliza├º├úo": 32, "F├¡sico": 65, "Passe": 45, "Marca├º├úo": 64, "Velocidade": 48, "Vis├úo de jogo": 46}';
        WHEN 'Goleiro:Finalizador' THEN v_base := '{"Finaliza├º├úo": 25, "F├¡sico": 58, "Passe": 45, "Marca├º├úo": 57, "Velocidade": 43, "Vis├úo de jogo": 52}';
        WHEN 'Goleiro:Driblador' THEN v_base := '{"Finaliza├º├úo": 24, "F├¡sico": 54, "Passe": 50, "Marca├º├úo": 55, "Velocidade": 50, "Vis├úo de jogo": 54}';
        WHEN 'Goleiro:Criador' THEN v_base := '{"Finaliza├º├úo": 22, "F├¡sico": 54, "Passe": 58, "Marca├º├úo": 56, "Velocidade": 43, "Vis├úo de jogo": 61}';
        WHEN 'Goleiro:Ra├ºudo' THEN v_base := '{"Finaliza├º├úo": 20, "F├¡sico": 63, "Passe": 44, "Marca├º├úo": 60, "Velocidade": 44, "Vis├úo de jogo": 50}';
        ELSE v_base := '{"Finaliza├º├úo": 61, "F├¡sico": 52, "Passe": 48, "Marca├º├úo": 35, "Velocidade": 59, "Vis├úo de jogo": 50}';
    END CASE;

    -- 2. Parse Height and Weight
    IF p_altura IS NOT NULL AND p_altura <> '' THEN
        v_normalized_altura := regexp_replace(replace(p_altura, ',', '.'), '[^0-9.]', '', 'g');
        BEGIN
            v_height_m := v_normalized_altura::NUMERIC;
            IF v_height_m < 1.1 OR v_height_m > 2.3 THEN v_height_m := NULL; END IF;
        EXCEPTION WHEN OTHERS THEN v_height_m := NULL;
        END;
    END IF;

    IF p_peso IS NOT NULL AND p_peso <> '' THEN
        v_normalized_peso := regexp_replace(p_peso, '\D', '', 'g');
        BEGIN
            v_weight_kg := v_normalized_peso::NUMERIC;
            IF v_weight_kg < 35 OR v_weight_kg > 160 THEN v_weight_kg := NULL; END IF;
        EXCEPTION WHEN OTHERS THEN v_weight_kg := NULL;
        END;
    END IF;

    -- 3. Calculate Severity and Weights
    IF v_height_m IS NOT NULL THEN
        IF v_height_m >= 1.93 THEN
            v_severity := v_severity + 2;
            pos_fisico := pos_fisico + 3; pos_marcacao := pos_marcacao + 2; pos_finalizacao := pos_finalizacao + 2;
            neg_velocidade := neg_velocidade + 3; neg_passe := neg_passe + 1; neg_visao := neg_visao + 1;
        ELSIF v_height_m >= 1.86 THEN
            v_severity := v_severity + 1;
            pos_fisico := pos_fisico + 2; pos_marcacao := pos_marcacao + 1; pos_finalizacao := pos_finalizacao + 1;
            neg_velocidade := neg_velocidade + 2; neg_passe := neg_passe + 1;
        ELSIF v_height_m <= 1.62 THEN
            v_severity := v_severity + 2;
            pos_velocidade := pos_velocidade + 3; pos_passe := pos_passe + 2; pos_visao := pos_visao + 2;
            neg_fisico := neg_fisico + 3; neg_marcacao := neg_marcacao + 2; neg_finalizacao := neg_finalizacao + 1;
        ELSIF v_height_m <= 1.70 THEN
            v_severity := v_severity + 1;
            pos_velocidade := pos_velocidade + 2; pos_passe := pos_passe + 1; pos_visao := pos_visao + 1;
            neg_fisico := neg_fisico + 2; neg_marcacao := neg_marcacao + 1;
        END IF;
    END IF;

    IF v_height_m IS NOT NULL AND v_weight_kg IS NOT NULL THEN
        v_bmi := v_weight_kg / (v_height_m * v_height_m);
        IF v_bmi >= 29 THEN
            v_severity := v_severity + 3;
            pos_fisico := pos_fisico + 3; pos_finalizacao := pos_finalizacao + 3; pos_marcacao := pos_marcacao + 1;
            neg_velocidade := neg_velocidade + 5; neg_passe := neg_passe + 1; neg_visao := neg_visao + 1;
        ELSIF v_bmi >= 26 THEN
            v_severity := v_severity + 2;
            pos_fisico := pos_fisico + 2; pos_finalizacao := pos_finalizacao + 2; pos_marcacao := pos_marcacao + 1;
            neg_velocidade := neg_velocidade + 3; neg_passe := neg_passe + 1; neg_visao := neg_visao + 1;
        ELSIF v_bmi >= 24.5 THEN
            v_severity := v_severity + 1;
            pos_fisico := pos_fisico + 2; pos_finalizacao := pos_finalizacao + 1;
            neg_velocidade := neg_velocidade + 2; neg_visao := neg_visao + 1;
        ELSIF v_bmi <= 18.5 THEN
            v_severity := v_severity + 3;
            pos_velocidade := pos_velocidade + 4; pos_passe := pos_passe + 2; pos_visao := pos_visao + 1;
            neg_fisico := neg_fisico + 4; neg_finalizacao := neg_finalizacao + 2; neg_marcacao := neg_marcacao + 1;
        ELSIF v_bmi <= 20.5 THEN
            v_severity := v_severity + 2;
            pos_velocidade := pos_velocidade + 3; pos_passe := pos_passe + 1; pos_visao := pos_visao + 1;
            neg_fisico := neg_fisico + 3; neg_finalizacao := neg_finalizacao + 1; neg_marcacao := neg_marcacao + 1;
        ELSIF v_bmi <= 21.5 THEN
            v_severity := v_severity + 1;
            pos_velocidade := pos_velocidade + 2; pos_passe := pos_passe + 1;
            neg_fisico := neg_fisico + 2; neg_marcacao := neg_marcacao + 1;
        END IF;
    ELSIF v_weight_kg IS NOT NULL THEN
        IF v_weight_kg >= 90 THEN
            v_severity := v_severity + 3;
            pos_fisico := pos_fisico + 2; pos_finalizacao := pos_finalizacao + 2; pos_marcacao := pos_marcacao + 1;
            neg_velocidade := neg_velocidade + 4; neg_passe := neg_passe + 1;
        ELSIF v_weight_kg >= 82 THEN
            v_severity := v_severity + 2;
            pos_fisico := pos_fisico + 2; pos_finalizacao := pos_finalizacao + 1;
            neg_velocidade := neg_velocidade + 2; neg_visao := neg_visao + 1;
        ELSIF v_weight_kg <= 60 THEN
            v_severity := v_severity + 2;
            pos_velocidade := pos_velocidade + 3; pos_passe := pos_passe + 1;
            neg_fisico := neg_fisico + 3; neg_finalizacao := neg_finalizacao + 1;
        END IF;
    END IF;

    -- 4. Distribute Points
    v_total := GREATEST(0, LEAST(5, ROUND(v_severity)::INT));

    IF pos_fisico > 0 THEN v_pos_weights := array_append(v_pos_weights, ROW('F├¡sico', pos_fisico)::attribute_weight); END IF;
    IF pos_marcacao > 0 THEN v_pos_weights := array_append(v_pos_weights, ROW('Marca├º├úo', pos_marcacao)::attribute_weight); END IF;
    IF pos_finalizacao > 0 THEN v_pos_weights := array_append(v_pos_weights, ROW('Finaliza├º├úo', pos_finalizacao)::attribute_weight); END IF;
    IF pos_velocidade > 0 THEN v_pos_weights := array_append(v_pos_weights, ROW('Velocidade', pos_velocidade)::attribute_weight); END IF;
    IF pos_passe > 0 THEN v_pos_weights := array_append(v_pos_weights, ROW('Passe', pos_passe)::attribute_weight); END IF;
    IF pos_visao > 0 THEN v_pos_weights := array_append(v_pos_weights, ROW('Vis├úo de jogo', pos_visao)::attribute_weight); END IF;

    IF neg_fisico > 0 THEN v_neg_weights := array_append(v_neg_weights, ROW('F├¡sico', neg_fisico)::attribute_weight); END IF;
    IF neg_marcacao > 0 THEN v_neg_weights := array_append(v_neg_weights, ROW('Marca├º├úo', neg_marcacao)::attribute_weight); END IF;
    IF neg_finalizacao > 0 THEN v_neg_weights := array_append(v_neg_weights, ROW('Finaliza├º├úo', neg_finalizacao)::attribute_weight); END IF;
    IF neg_velocidade > 0 THEN v_neg_weights := array_append(v_neg_weights, ROW('Velocidade', neg_velocidade)::attribute_weight); END IF;
    IF neg_passe > 0 THEN v_neg_weights := array_append(v_neg_weights, ROW('Passe', neg_passe)::attribute_weight); END IF;
    IF neg_visao > 0 THEN v_neg_weights := array_append(v_neg_weights, ROW('Vis├úo de jogo', neg_visao)::attribute_weight); END IF;

    v_pos_dist := distribute_points(v_total, v_pos_weights);
    v_neg_dist := distribute_points(v_total, v_neg_weights);

    v_mod_fisico := COALESCE((v_pos_dist->>'F├¡sico')::INT, 0) - COALESCE((v_neg_dist->>'F├¡sico')::INT, 0);
    v_mod_marcacao := COALESCE((v_pos_dist->>'Marca├º├úo')::INT, 0) - COALESCE((v_neg_dist->>'Marca├º├úo')::INT, 0);
    v_mod_finalizacao := COALESCE((v_pos_dist->>'Finaliza├º├úo')::INT, 0) - COALESCE((v_neg_dist->>'Finaliza├º├úo')::INT, 0);
    v_mod_velocidade := COALESCE((v_pos_dist->>'Velocidade')::INT, 0) - COALESCE((v_neg_dist->>'Velocidade')::INT, 0);
    v_mod_passe := COALESCE((v_pos_dist->>'Passe')::INT, 0) - COALESCE((v_neg_dist->>'Passe')::INT, 0);
    v_mod_visao := COALESCE((v_pos_dist->>'Vis├úo de jogo')::INT, 0) - COALESCE((v_neg_dist->>'Vis├úo de jogo')::INT, 0);

    v_modifiers := jsonb_build_object(
        'F├¡sico', v_mod_fisico,
        'Marca├º├úo', v_mod_marcacao,
        'Finaliza├º├úo', v_mod_finalizacao,
        'Velocidade', v_mod_velocidade,
        'Passe', v_mod_passe,
        'Vis├úo de jogo', v_mod_visao
    );

    v_final := jsonb_build_object(
        'F├¡sico', GREATEST(1, LEAST(99, (v_base->>'F├¡sico')::INT + v_mod_fisico)),
        'Marca├º├úo', GREATEST(1, LEAST(99, (v_base->>'Marca├º├úo')::INT + v_mod_marcacao)),
        'Finaliza├º├úo', GREATEST(1, LEAST(99, (v_base->>'Finaliza├º├úo')::INT + v_mod_finalizacao)),
        'Velocidade', GREATEST(1, LEAST(99, (v_base->>'Velocidade')::INT + v_mod_velocidade)),
        'Passe', GREATEST(1, LEAST(99, (v_base->>'Passe')::INT + v_mod_passe)),
        'Vis├úo de jogo', GREATEST(1, LEAST(99, (v_base->>'Vis├úo de jogo')::INT + v_mod_visao))
    );

    RETURN jsonb_build_object(
        'base', v_base,
        'modifiers', v_modifiers,
        'final', v_final
    );
END;
$function$
